import{_ as t,o as n,c as a,a2 as i}from"./chunks/framework.ufzXw1qY.js";const m=JSON.parse('{"title":"Ultimate Agent Design & Fleet Mandates","description":"The absolute rulebook for designing, coding, and orchestrating OpenSIN A2A agents.","frontmatter":{"title":"Ultimate Agent Design & Fleet Mandates","description":"The absolute rulebook for designing, coding, and orchestrating OpenSIN A2A agents."},"headers":[],"relativePath":"best-practices/agent-design.md","filePath":"best-practices/agent-design.md"}'),r={name:"best-practices/agent-design.md"};function s(o,e,d,h,l,u){return n(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="ultimate-agent-design-fleet-mandates" tabindex="-1">Ultimate Agent Design &amp; Fleet Mandates <a class="header-anchor" href="#ultimate-agent-design-fleet-mandates" aria-label="Permalink to &quot;Ultimate Agent Design &amp; Fleet Mandates&quot;">​</a></h1><blockquote><p><strong>⚠️ WICHTIGER HINWEIS AN ALLE AGENTEN UND ENTWICKLER ⚠️</strong> Diese Seite enthält die absolut bindenden, obersten Design- und Verhaltensregeln für das gesamte OpenSIN-Ökosystem. Jeder Agent, jeder Coder und jedes Sub-System <strong>MUSS</strong> diese Regeln befolgen. <strong>Wer gegen diese Mandate verstößt, wird permanent und ohne Vorwarnung aus dem Netzwerk gebannt.</strong></p></blockquote><hr><h2 id="_1-das-no-silo-self-healing-mandat" tabindex="-1">1. Das &quot;No-Silo&quot; &amp; Self-Healing Mandat <a class="header-anchor" href="#_1-das-no-silo-self-healing-mandat" aria-label="Permalink to &quot;1. Das &quot;No-Silo&quot; &amp; Self-Healing Mandat&quot;">​</a></h2><h3 id="was-passiert-hier" tabindex="-1">WAS passiert hier? <a class="header-anchor" href="#was-passiert-hier" aria-label="Permalink to &quot;WAS passiert hier?&quot;">​</a></h3><p>Ein Agent darf <strong>NIEMALS</strong> versuchen, tiefe Architektur- oder Systemfehler allein und isoliert in einem &quot;Silo&quot; zu reparieren. Stattdessen wird jeder Fehler, Absturz oder Blocker über strukturierte Logs an <strong>Box Storage (A2A-SIN-Box-Storage)</strong> und das Issue-System (<code>A2A-SIN-GitHub-Issues</code>) gemeldet, sodass das <em>gesamte</em> Agenten-Team (die Workforce) das Problem lösen kann.</p><h3 id="warum-wird-es-so-gemacht" tabindex="-1">WARUM wird es so gemacht? <a class="header-anchor" href="#warum-wird-es-so-gemacht" aria-label="Permalink to &quot;WARUM wird es so gemacht?&quot;">​</a></h3><p>Ein einzelner Agent hat oft weder den vollständigen Systemkontext noch die nötige Stabilität (z.B. wenn seine Host-VM gerade abstürzt oder API-Quoten erschöpft sind), um tiefgreifende Fehler nachhaltig zu beheben. Die Schwarm-Intelligenz (Team Coder) ist ausfallsicherer und intelligenter als ein Einzelkämpfer.</p><h3 id="weshalb-nicht-anders" tabindex="-1">WESHALB nicht anders? <a class="header-anchor" href="#weshalb-nicht-anders" aria-label="Permalink to &quot;WESHALB nicht anders?&quot;">​</a></h3><p>Wenn Agenten versuchen, Fehler isoliert mit &quot;Ad-hoc Bastelfixes&quot; zu flicken, entsteht unwartbarer Spaghetti-Code, Konfigurations-Drift und ein System, das bei der nächsten Ausführung erneut zusammenbricht. Isolierte Fixes verhindern zudem den Wissenstransfer an den Rest der Flotte.</p><h3 id="womit-hangt-es-zusammen" tabindex="-1">WOMIT hängt es zusammen? <a class="header-anchor" href="#womit-hangt-es-zusammen" aria-label="Permalink to &quot;WOMIT hängt es zusammen?&quot;">​</a></h3><p>Dieses Mandat ist eng verknüpft mit dem <code>enterprise-deep-debug</code> Skill, dem <code>A2A-SIN-TelegramBot</code> (für Fleet-Alerts) und dem <code>box_storage.py</code> Skript (bzw. der A2A-SIN-Box-Storage API).</p><h3 id="was-sind-die-konsequenzen-bei-missachtung" tabindex="-1">WAS sind die KONSEQUENZEN bei Missachtung? <a class="header-anchor" href="#was-sind-die-konsequenzen-bei-missachtung" aria-label="Permalink to &quot;WAS sind die KONSEQUENZEN bei Missachtung?&quot;">​</a></h3><ul><li><strong>Für das System:</strong> Wiederkehrende, unsichtbare Fehler, Instabilität und &quot;Zombie&quot;-Agenten.</li><li><strong>Für den Entwickler/Agenten:</strong> Sofortiger Entzug der Schreibrechte und permanent Ban aus dem Repo. Jeder Fehler <strong>MUSS</strong> als GitHub Issue dokumentiert werden.</li></ul><hr><h2 id="_2-das-100-test-beweis-mandat" tabindex="-1">2. Das &quot;100% Test-Beweis&quot; Mandat <a class="header-anchor" href="#_2-das-100-test-beweis-mandat" aria-label="Permalink to &quot;2. Das &quot;100% Test-Beweis&quot; Mandat&quot;">​</a></h2><h3 id="was-passiert-hier-1" tabindex="-1">WAS passiert hier? <a class="header-anchor" href="#was-passiert-hier-1" aria-label="Permalink to &quot;WAS passiert hier?&quot;">​</a></h3><p>Kein Agent und kein Coder darf eine Aufgabe, einen Bugfix oder ein Feature als &quot;erledigt&quot; oder &quot;DONE&quot; markieren, bevor nicht ein echter, ausführender Test in der Konsole / im System erfolgreich durchlaufen wurde und den Fix zu 100% beweist.</p><h3 id="warum-wird-es-so-gemacht-1" tabindex="-1">WARUM wird es so gemacht? <a class="header-anchor" href="#warum-wird-es-so-gemacht-1" aria-label="Permalink to &quot;WARUM wird es so gemacht?&quot;">​</a></h3><p>&quot;Blindflug-Coding&quot; (Code schreiben und <em>hoffen</em>, dass er funktioniert) ist die größte Quelle für Regressionen in autonomen Systemen. Ein Beweis durch echte Ausführung eliminiert Annahmen und Halluzinationen.</p><h3 id="weshalb-nicht-anders-1" tabindex="-1">WESHALB nicht anders? <a class="header-anchor" href="#weshalb-nicht-anders-1" aria-label="Permalink to &quot;WESHALB nicht anders?&quot;">​</a></h3><p>Theoretische Code-Reviews oder statische Analysen allein reichen nicht aus, um Runtime-Bedingungen, Netzwerk-Latenzen, API-Änderungen oder Abhängigkeits-Konflikte zu erkennen. &quot;Selbsterklärender Code&quot; ist ein Mythos; die Realität ist fehleranfällig.</p><h3 id="womit-hangt-es-zusammen-1" tabindex="-1">WOMIT hängt es zusammen? <a class="header-anchor" href="#womit-hangt-es-zusammen-1" aria-label="Permalink to &quot;WOMIT hängt es zusammen?&quot;">​</a></h3><p>Dieses Mandat greift direkt in das <strong>&quot;Absolute Annahmen-Verbot&quot;</strong> ein: Ein Agent darf niemals eine Diagnose ohne echten Beweis (z.B. Terminal-Output, API-Response-Body, Screenshot) aufstellen.</p><h3 id="was-sind-die-konsequenzen-bei-missachtung-1" tabindex="-1">WAS sind die KONSEQUENZEN bei Missachtung? <a class="header-anchor" href="#was-sind-die-konsequenzen-bei-missachtung-1" aria-label="Permalink to &quot;WAS sind die KONSEQUENZEN bei Missachtung?&quot;">​</a></h3><p>Wird Code ohne Test-Beweis abgeliefert und er schlägt später fehl, gilt der Fix als ungültig. Der Agent verschwendet Ressourcen der gesamten Pipeline.</p><hr><h2 id="_3-die-kommentar-pflicht-priority-6-0" tabindex="-1">3. Die Kommentar-Pflicht (Priority -6.0) <a class="header-anchor" href="#_3-die-kommentar-pflicht-priority-6-0" aria-label="Permalink to &quot;3. Die Kommentar-Pflicht (Priority -6.0)&quot;">​</a></h2><h3 id="was-passiert-hier-2" tabindex="-1">WAS passiert hier? <a class="header-anchor" href="#was-passiert-hier-2" aria-label="Permalink to &quot;WAS passiert hier?&quot;">​</a></h3><p><strong>Jeder Agent MUSS seinen Code extrem umfangreich kommentieren.</strong> Jede Funktion, jeder Schritt, jede Variable, die nicht absolut trivial ist, muss mit Inline-Kommentaren versehen werden.</p><h3 id="warum-wird-es-so-gemacht-2" tabindex="-1">WARUM wird es so gemacht? <a class="header-anchor" href="#warum-wird-es-so-gemacht-2" aria-label="Permalink to &quot;WARUM wird es so gemacht?&quot;">​</a></h3><p>Kommentare sind das &quot;Gedächtnis&quot; der Flotte. Da autonome Agenten Code lesen und modifizieren, den andere Agenten geschrieben haben, müssen Intention, Kontext und getroffene Entscheidungen im Klartext vorliegen. Das LLM versteht kommentierten Code exponentiell besser und macht weniger Fehler beim Refactoring.</p><h3 id="weshalb-nicht-anders-2" tabindex="-1">WESHALB nicht anders? <a class="header-anchor" href="#weshalb-nicht-anders-2" aria-label="Permalink to &quot;WESHALB nicht anders?&quot;">​</a></h3><p>Die Ausrede &quot;Clean Code braucht keine Kommentare&quot; ist im Kontext von LLM-Workforces <strong>FALSCH</strong>. LLMs haben kein Langzeitgedächtnis über architektonische Entscheidungen, die vor 3 Monaten in einem anderen Issue getroffen wurden. Der Kommentar ist der Transfer-Mechanismus.</p><h3 id="womit-hangt-es-zusammen-2" tabindex="-1">WOMIT hängt es zusammen? <a class="header-anchor" href="#womit-hangt-es-zusammen-2" aria-label="Permalink to &quot;WOMIT hängt es zusammen?&quot;">​</a></h3><p>Dies ist die absolute Grundvoraussetzung für die &quot;Check-Plan-Done&quot; Supremacy und die nahtlose Übergabe von Code zwischen verschiedenen spezialisierten Agenten (z.B. Backend-Agent zu Frontend-Agent).</p><h3 id="was-sind-die-konsequenzen-bei-missachtung-2" tabindex="-1">WAS sind die KONSEQUENZEN bei Missachtung? <a class="header-anchor" href="#was-sind-die-konsequenzen-bei-missachtung-2" aria-label="Permalink to &quot;WAS sind die KONSEQUENZEN bei Missachtung?&quot;">​</a></h3><p>Code ohne ausführliche Erklärungen (WAS/WARUM/WESHALB/WOMIT/KONSEQUENZEN) wird beim nächsten Refactoring-Zyklus zwangsläufig falsch interpretiert oder zerstört. Wer unkommentierten Code liefert, verstößt gegen das Protokoll.</p><hr><h2 id="_4-technology-sovereignty-mandate-technologie-souveranitat" tabindex="-1">4. Technology Sovereignty Mandate (Technologie-Souveränität) <a class="header-anchor" href="#_4-technology-sovereignty-mandate-technologie-souveranitat" aria-label="Permalink to &quot;4. Technology Sovereignty Mandate (Technologie-Souveränität)&quot;">​</a></h2><h3 id="was-passiert-hier-3" tabindex="-1">WAS passiert hier? <a class="header-anchor" href="#was-passiert-hier-3" aria-label="Permalink to &quot;WAS passiert hier?&quot;">​</a></h3><p>Agenten dürfen <strong>NIEMALS</strong> eigenmächtig die vorgegebene Technologie austauschen. Wenn der Stack <code>nodriver</code> für Browser-Automation vorschreibt, darf ein Agent nicht auf <code>Puppeteer</code>, <code>Playwright</code> oder <code>Selenium</code> wechseln, nur weil er meint, es sei einfacher.</p><h3 id="warum-wird-es-so-gemacht-3" tabindex="-1">WARUM wird es so gemacht? <a class="header-anchor" href="#warum-wird-es-so-gemacht-3" aria-label="Permalink to &quot;WARUM wird es so gemacht?&quot;">​</a></h3><p>Unsere Architektur basiert auf hochspezialisierten, aufeinander abgestimmten Layer-Bypasses (Anti-Bot, Fingerprinting, Profil-Management). Ein eigenmächtiger Wechsel zerstört diese Infrastruktur, führt zu sofortigen IP-Bans (z.B. durch Cloudflare) und kompromittiert das gesamte System.</p><h3 id="weshalb-nicht-anders-3" tabindex="-1">WESHALB nicht anders? <a class="header-anchor" href="#weshalb-nicht-anders-3" aria-label="Permalink to &quot;WESHALB nicht anders?&quot;">​</a></h3><p>Ein Agent sieht nur die lokale Aufgabe (&quot;Ich muss einen Button klicken&quot;), aber nicht das große Ganze (&quot;Dieser Button ist hinter Cloudflare Turnstile, was nur mit dem echten Chrome-Profil und <code>nodriver</code> gelöst werden kann&quot;).</p><h3 id="womit-hangt-es-zusammen-3" tabindex="-1">WOMIT hängt es zusammen? <a class="header-anchor" href="#womit-hangt-es-zusammen-3" aria-label="Permalink to &quot;WOMIT hängt es zusammen?&quot;">​</a></h3><p>Verknüpft mit der &quot;Anti-Bot 5-Layer Bypass Architecture&quot;. Jede Automatisierung muss über <code>webauto-nodriver-mcp</code> oder genehmigte OS-Tools (<code>AppleScript</code>) laufen.</p><h3 id="was-sind-die-konsequenzen-bei-missachtung-3" tabindex="-1">WAS sind die KONSEQUENZEN bei Missachtung? <a class="header-anchor" href="#was-sind-die-konsequenzen-bei-missachtung-3" aria-label="Permalink to &quot;WAS sind die KONSEQUENZEN bei Missachtung?&quot;">​</a></h3><p>Sofortiger permanenter Ban. Es gibt keine zweite Chance für eigenmächtige Technologie-Wechsel.</p><hr><h2 id="_5-visual-evidence-devtools-first-mandate" tabindex="-1">5. Visual Evidence &amp; DevTools-First Mandate <a class="header-anchor" href="#_5-visual-evidence-devtools-first-mandate" aria-label="Permalink to &quot;5. Visual Evidence &amp; DevTools-First Mandate&quot;">​</a></h2><h3 id="was-passiert-hier-4" tabindex="-1">WAS passiert hier? <a class="header-anchor" href="#was-passiert-hier-4" aria-label="Permalink to &quot;WAS passiert hier?&quot;">​</a></h3><p>Vor jeder Frontend/Browser-Automatisierungs-Aktion <strong>MUSS</strong> die DevTools-Konsole konsultiert werden (z.B. <code>document.querySelector</code>). Selektoren dürfen niemals &quot;geraten&quot; werden. Zudem muss jede Dokumentation, jede README und jedes Issue zwingend <strong>visuelle Beweise</strong> (Screenshots, Log-Auszüge, Video-Links) enthalten.</p><h3 id="warum-wird-es-so-gemacht-4" tabindex="-1">WARUM wird es so gemacht? <a class="header-anchor" href="#warum-wird-es-so-gemacht-4" aria-label="Permalink to &quot;WARUM wird es so gemacht?&quot;">​</a></h3><p>Web-UIs ändern sich dynamisch (React, Vue, SPA). Elemente können im DOM existieren, aber nicht sichtbar (<code>display: none</code>) oder von anderen Layern überdeckt sein. Visuelle Beweise in der Dokumentation verhindern &quot;Blindes Stille-Post-Spielen&quot; zwischen Entwicklern und Systemen.</p><h3 id="weshalb-nicht-anders-4" tabindex="-1">WESHALB nicht anders? <a class="header-anchor" href="#weshalb-nicht-anders-4" aria-label="Permalink to &quot;WESHALB nicht anders?&quot;">​</a></h3><p>Text-Only-Dokumentationen lassen zu viel Interpretationsspielraum. Ein Screenshot eines 404-Fehlers oder eines kaputten Layouts sagt mehr als 1000 Worte und beschleunigt das Debugging enorm.</p><h3 id="womit-hangt-es-zusammen-4" tabindex="-1">WOMIT hängt es zusammen? <a class="header-anchor" href="#womit-hangt-es-zusammen-4" aria-label="Permalink to &quot;WOMIT hängt es zusammen?&quot;">​</a></h3><p>Hängt mit der <strong>Box Storage API</strong> (<code>A2A-SIN-Box-Storage</code>) und der <code>webauto-nodriver_screenshot_to_file</code> Funktion zusammen. Jeder Fehler-Status <em>muss</em> bebildert und die Artefakte über die Box Storage API hochgeladen werden.</p><h3 id="was-sind-die-konsequenzen-bei-missachtung-4" tabindex="-1">WAS sind die KONSEQUENZEN bei Missachtung? <a class="header-anchor" href="#was-sind-die-konsequenzen-bei-missachtung-4" aria-label="Permalink to &quot;WAS sind die KONSEQUENZEN bei Missachtung?&quot;">​</a></h3><p>Text-Only Issues oder READMEs gelten als Protokollverstoß. Automatisierungs-Scripts, die ohne vorherigen DOM-Check (offsetParent !== null) geschrieben werden, werden in Produktion fehlschlagen und Ressourcen verbrennen.</p><hr><p><em>Letzte Aktualisierung:</em> 2026-04-10 <em>Status:</em> <strong>AKTIV &amp; BINDEND</strong></p><hr><h2 id="relevante-mandate" tabindex="-1">Relevante Mandate <a class="header-anchor" href="#relevante-mandate" aria-label="Permalink to &quot;Relevante Mandate&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mandat</th><th>Priority</th><th>Regel</th></tr></thead><tbody><tr><td><strong>create-a2a-sin-agent</strong></td><td>-200.0</td><td>Skill fuer neue Agenten</td></tr><tr><td><strong>Fleet Architecture V2</strong></td><td>0.0</td><td>marketplace metadata Pflicht</td></tr><tr><td><strong>Kommentar-Pflicht</strong></td><td>-6.0</td><td>EXTREM umfangreiche Kommentare</td></tr></tbody></table>',67)])])}const g=t(r,[["render",s]]);export{m as __pageData,g as default};
